// Story-graph reachability lint (overhaul Phase 5): prove an adventure is FINISHABLE before
// it ever reaches a player.
//
// Stage 7 checks prose contradictions. It cannot see the failure that actually shipped: a
// guide whose objective atoms nothing awards, whose only social route names a corpse, or whose
// chapter has nobody alive to talk to. Those are graph properties, not narrative ones, and
// they are decidable deterministically - so they are a gate, not a warning.
//
// Runs at the end of stage 8, immediately before `guide_ready`.

import { evaluatePredicate, listMilestoneAtoms } from '../story/evaluate.ts'
import { canonicalizeAtomSlug } from '../story/atoms.ts'
import { minimalSatisfyingAtoms } from './guaranteed-route.ts'

export type LintSeverity = 'error' | 'warning'

export interface LintFinding {
  severity: LintSeverity
  code: string
  message: string
  /** The row this is about, when it is about one. */
  target?: { table: string; id: string }
}

export interface GraphObjective {
  id: string
  chapterId: string
  index: number
  title: string
  completionPredicates: unknown
  /** Code-authored rescue route (Phase 4); its atoms count as a route of last resort. */
  guaranteedRouteAtoms?: string[]
}

export interface GraphNpc {
  id: string
  name: string
  chapterId: string | null
  /** 'alive' | 'dead' | 'absent' */
  initialState: string
}

export interface GraphEncounter {
  id: string
  chapterId: string | null
  type: string
  outcomeAtoms?: string[]
}

export interface GraphIngredient {
  id: string
  chapterId: string | null
  awardsAtoms?: string[]
}

export interface GraphEnding {
  id: string
  title: string
  /** Positive-weight objective signals only - what this ending NEEDS to be reachable. */
  objectiveSignals: { objectiveId: string; outcome: 'completed' | 'failed'; weight: number }[]
  /** NPC-state signals, for checking they key on someone play can actually reach. */
  npcSignals?: { npcId: string; state: string; weight: number }[]
}

export interface StoryGraph {
  chapters: { id: string; index: number; title: string }[]
  objectives: GraphObjective[]
  npcs: GraphNpc[]
  encounters: GraphEncounter[]
  ingredients: GraphIngredient[]
  endings: GraphEnding[]
}

/** Atoms any authored route can award, canonicalized for comparison. */
function awardableAtoms(graph: StoryGraph): Set<string> {
  const set = new Set<string>()
  const add = (atoms: readonly string[] | undefined) => {
    for (const a of atoms ?? []) {
      const slug = canonicalizeAtomSlug(a)
      if (slug) set.add(slug)
    }
  }
  for (const e of graph.encounters) add(e.outcomeAtoms)
  for (const i of graph.ingredients) add(i.awardsAtoms)
  return set
}

/**
 * How many DISTINCT authored routes can complete this objective? The Three-Clue Rule applied
 * to progression: one route is a single point of failure, and the guaranteed route is the
 * always-present safety net, not a substitute for authoring.
 */
export function routeCount(objective: GraphObjective, graph: StoryGraph): number {
  const needed = minimalSatisfyingAtoms(objective.completionPredicates)
  if (!needed || needed.length === 0) return 0
  const neededSlugs = needed.map(canonicalizeAtomSlug)
  const covers = (atoms: readonly string[] | undefined): boolean => {
    if (!atoms || atoms.length === 0) return false
    const have = new Set(atoms.map(canonicalizeAtomSlug))
    return neededSlugs.every((a) => have.has(a))
  }
  let count = 0
  for (const e of graph.encounters) if (covers(e.outcomeAtoms)) count++
  for (const i of graph.ingredients) if (covers(i.awardsAtoms)) count++
  return count
}

export const MIN_ROUTES_PER_OBJECTIVE = 2

/**
 * The gate. Errors mean "this adventure can lock"; warnings mean "this adventure is thin".
 * Deliberately structural throughout - no word-signal matching, no LLM.
 */
export function lintStoryGraph(graph: StoryGraph): LintFinding[] {
  const findings: LintFinding[] = []
  const awardable = awardableAtoms(graph)

  // 1. Every objective must be completable by SOMETHING.
  for (const objective of graph.objectives) {
    const atoms = listMilestoneAtoms(objective.completionPredicates)
    const all = [...atoms.flags, ...atoms.events, ...atoms.facts]
    if (all.length === 0) {
      findings.push({
        severity: 'error',
        code: 'objective_no_claimable_atom',
        message: `"${objective.title}" has no atom live play can ever claim - it can never complete.`,
        target: { table: 'objectives', id: objective.id },
      })
      continue
    }
    // Already true before anyone plays. An unset flag now reads false (story/evaluate.ts), which
    // is what makes "the deadline has not passed" expressible - but it also means a predicate
    // built ONLY from negative clauses holds on turn zero. That is the phantom-completion shape:
    // an objective the party is handed and credited with in the same breath, having done
    // nothing. Cheap to detect, and the exact regression the evaluator change could otherwise
    // introduce.
    if (evaluatePredicate(objective.completionPredicates, { facts: {}, flags: {}, events: new Set() })) {
      findings.push({
        severity: 'error',
        code: 'objective_satisfied_at_start',
        message:
          `"${objective.title}" is already complete before play begins - its predicate holds ` +
          `against an empty world, so the party is credited for doing nothing.`,
        target: { table: 'objectives', id: objective.id },
      })
      continue
    }
    const routes = routeCount(objective, graph)
    const rescue = (objective.guaranteedRouteAtoms ?? []).length > 0
    if (routes === 0 && !rescue) {
      findings.push({
        severity: 'error',
        code: 'objective_unreachable',
        message:
          `"${objective.title}" has NO route that awards its completion atoms ` +
          `(${all.join(', ')}) and no guaranteed route. The party could not finish it by any means.`,
        target: { table: 'objectives', id: objective.id },
      })
    } else if (routes < MIN_ROUTES_PER_OBJECTIVE) {
      // Three-Clue Rule: the rescue route is the third clue, not the first.
      findings.push({
        severity: 'warning',
        code: 'objective_thin_routes',
        message:
          `"${objective.title}" has ${routes} authored route(s); ${MIN_ROUTES_PER_OBJECTIVE} or more ` +
          'means a party that misses one can still get there without the rescue route firing.',
        target: { table: 'objectives', id: objective.id },
      })
    }
  }

  // 2. Every chapter needs a living PERSON to talk to. The Sunken Chapel failure - whose two
  //    "NPCs" were a dead expedition (a group) and an absent force, so there was nobody to
  //    converse with even though the table had rows in it.
  const liveByChapter = new Map<string, number>()
  for (const npc of graph.npcs) {
    if (npc.initialState === 'dead' || npc.initialState === 'absent') continue
    if (!npc.chapterId) continue
    liveByChapter.set(npc.chapterId, (liveByChapter.get(npc.chapterId) ?? 0) + 1)
  }
  const globalLiving = graph.npcs.some(
    (n) => !n.chapterId && n.initialState !== 'dead' && n.initialState !== 'absent',
  )
  for (const chapter of graph.chapters) {
    if ((liveByChapter.get(chapter.id) ?? 0) === 0 && !globalLiving) {
      findings.push({
        severity: 'error',
        code: 'chapter_no_living_npc',
        message:
          `Chapter ${chapter.index + 1} ("${chapter.title}") has no living, present NPC. ` +
          'No social encounter can open there and live play cannot author its way out.',
        target: { table: 'chapters', id: chapter.id },
      })
    }
  }

  // 2b. An ending resting on a force or faction having feelings can never fire: only people
  //     accumulate disposition. Live 2026-07-23 an entire adventure's endings keyed on
  //     "The Blighted Heart = allied / dead / alive" - a corrupting phenomenon authored as an
  //     NPC. Those endings were unreachable by construction.
  const npcById = new Map(graph.npcs.map((n) => [n.id, n]))
  for (const ending of graph.endings) {
    for (const signal of ending.npcSignals ?? []) {
      if (signal.weight <= 0) continue
      const npc = npcById.get(signal.npcId)
      if (!npc) continue
      if (signal.state === 'allied' || signal.state === 'hostile') {
        // Disposition only ever moves for someone the party can actually interact with.
        if (npc.initialState === 'absent') {
          findings.push({
            severity: 'warning',
            code: 'ending_needs_absent_npc_rapport',
            message:
              `Ending "${ending.title}" needs ${npc.name} to become ${signal.state}, but they are ` +
              'authored as absent - nothing in play can build rapport with someone never present.',
            target: { table: 'endings', id: ending.id },
          })
        }
      }
    }
  }

  // 3. Every ending must be reachable from some achievable combination of objective outcomes.
  //    Each objective can end completed OR failed (Phase 4), so a positive signal is
  //    satisfiable as long as it names a real objective.
  const objectiveIds = new Set(graph.objectives.map((o) => o.id))
  for (const ending of graph.endings) {
    const positive = ending.objectiveSignals.filter((s) => s.weight > 0)
    if (positive.length === 0) continue // dial/NPC-driven ending; §8's own checks cover it
    const reachable = positive.some((s) => objectiveIds.has(s.objectiveId))
    if (!reachable) {
      findings.push({
        severity: 'error',
        code: 'ending_unreachable',
        message: `Ending "${ending.title}" keys only on objectives that do not exist in this guide.`,
        target: { table: 'endings', id: ending.id },
      })
    }
  }

  // 4. At least one ending must survive a failure-heavy run. Phase 4 lets objectives FAIL, so
  //    a guide whose every ending demands completions has nowhere to land a bad run.
  if (graph.endings.length > 0 && graph.objectives.length > 0) {
    const failureTolerant = graph.endings.some((e) => {
      const positive = e.objectiveSignals.filter((s) => s.weight > 0)
      return positive.length === 0 || positive.some((s) => s.outcome === 'failed')
    })
    if (!failureTolerant) {
      findings.push({
        severity: 'warning',
        code: 'no_failure_ending',
        message:
          'Every ending requires completed objectives. A run where the party fails forward has ' +
          'no ending that fits it - author one keyed on a failed outcome.',
      })
    }
  }

  // 5. Orphan awards: an encounter/ingredient crediting an atom no objective reads is dead
  //    progression - harmless, but a sign the author lost the thread.
  const objectiveAtoms = new Set<string>()
  for (const o of graph.objectives) {
    const atoms = listMilestoneAtoms(o.completionPredicates)
    for (const a of [...atoms.flags, ...atoms.events, ...atoms.facts]) {
      const slug = canonicalizeAtomSlug(a)
      if (slug) objectiveAtoms.add(slug)
    }
  }
  const orphans = [...awardable].filter((a) => !objectiveAtoms.has(a))
  if (orphans.length > 0) {
    findings.push({
      severity: 'warning',
      code: 'orphan_award_atoms',
      message: `These awarded atoms match no objective predicate: ${orphans.slice(0, 6).join(', ')}.`,
    })
  }

  return findings
}

export function hasBlockingErrors(findings: readonly LintFinding[]): boolean {
  return findings.some((f) => f.severity === 'error')
}
